# Phase 1: Analyze the Fix

This is a patch for PtrUseVisitor:

[PtrUseVisitor] Support llvm.structured.gep
This commit adds support the @llvm.structued.gep instruction when computing a pointer offset. Even if the physical layout of the pointed element is not yet known (hence SGEP), we can still determine which element is being accessed. So the offset value here is coherent in the context of LLVM, which is the important part.
diff --git a/llvm/include/llvm/Analysis/PtrUseVisitor.h b/llvm/include/llvm/Analysis/PtrUseVisitor.h
index 0858d8aee2186..27b8ca9ebef98 100644
--- a/llvm/include/llvm/Analysis/PtrUseVisitor.h
+++ b/llvm/include/llvm/Analysis/PtrUseVisitor.h
@@ -175,6 +175,12 @@ class PtrUseVisitorBase {
   /// This routine does the heavy lifting of the pointer walk by computing
   /// offsets and looking through GEPs.
   bool adjustOffsetForGEP(GetElementPtrInst &GEPI);
+
+  /// Walk the operands of a StructuredGEP and adjust the offset as appropriate.
+  /// The returned offset can be compared against other offsets during an
+  /// analysis, but should not be stored as constant in the IR as it may not
+  /// represent the actual physical offset.
+  bool adjustOffsetForSGEP(StructuredGEPInst &SGEP);
 };

 } // end namespace detail
@@ -283,10 +289,24 @@ class PtrUseVisitor : protected InstVisitor<DerivedT>,
     enqueueUsers(GEPI);
   }

+  void visitStructuredGEPInst(StructuredGEPInst &SGEP) {
+    if (SGEP.use_empty())
+      return;
+
+    if (!adjustOffsetForSGEP(SGEP)) {
+      IsOffsetKnown = false;
+      Offset = APInt();
+    }
+    enqueueUsers(SGEP);
+  }
+
   // No-op intrinsics which we know don't escape the pointer to logic in
   // some other function.
   void visitMemIntrinsic(MemIntrinsic &I) {}
   void visitIntrinsicInst(IntrinsicInst &II) {
+    if (auto *SGEP = dyn_cast<StructuredGEPInst>(&II))
+      return visitStructuredGEPInst(*SGEP);
+
     switch (II.getIntrinsicID()) {
     default:
       return Base::visitIntrinsicInst(II);
diff --git a/llvm/lib/Analysis/PtrUseVisitor.cpp b/llvm/lib/Analysis/PtrUseVisitor.cpp
index 9c79546f491ef..cce18b9ab626f 100644
--- a/llvm/lib/Analysis/PtrUseVisitor.cpp
+++ b/llvm/lib/Analysis/PtrUseVisitor.cpp
@@ -41,3 +41,36 @@ bool detail::PtrUseVisitorBase::adjustOffsetForGEP(GetElementPtrInst &GEPI) {

   return false;
 }
+
+bool detail::PtrUseVisitorBase::adjustOffsetForSGEP(StructuredGEPInst &SGEP) {
+  if (!IsOffsetKnown)
+    return false;
+
+  Type *CurrentType = SGEP.getBaseType();
+  unsigned int OffsetBitWidth = DL.getIndexTypeSizeInBits(SGEP.getType());
+  APInt TmpOffset(OffsetBitWidth, 0);
+
+  for (unsigned I = 0; I < SGEP.getNumIndices(); I++) {
+    Value *V = SGEP.getIndexOperand(I);
+    ConstantInt *CI = dyn_cast<ConstantInt>(V);
+    if (!CI) {
+      IsOffsetKnown = false;
+      return false;
+    }
+
+    if (ArrayType *AT = dyn_cast<ArrayType>(CurrentType)) {
+      uint32_t EltTypeSize = DL.getTypeSizeInBits(AT->getElementType()) / 8;
+      TmpOffset += CI->getZExtValue() * EltTypeSize;
+      CurrentType = AT->getElementType();
+    } else if (StructType *ST = dyn_cast<StructType>(CurrentType)) {
+      const auto &STL = DL.getStructLayout(ST);
+      TmpOffset += STL->getElementOffset(CI->getZExtValue());
+      CurrentType = ST->getElementType(CI->getZExtValue());
+    } else {
+      llvm_unreachable("unimplemented");
+    }
+  }
+
+  Offset += TmpOffset;
+  return true;
+}


