188 /// A base class for visitors over the uses of a pointer value.
189 ///
190 /// Once constructed, a user can call \c visit on a pointer value, and this
191 /// will walk its uses and visit each instruction using an InstVisitor. It also
192 /// provides visit methods which will recurse through any pointer-to-pointer
193 /// transformations such as GEPs and bitcasts.
194 ///
195 /// During the visit, the current Use* being visited is available to the
196 /// subclass, as well as the current offset from the original base pointer if
197 /// known.
198 ///
199 /// The recursive visit of uses is accomplished with a worklist, so the only
200 /// ordering guarantee is that an instruction is visited before any uses of it
201 /// are visited. Note that this does *not* mean before any of its users are
202 /// visited! This is because users can be visited multiple times due to
203 /// multiple, different uses of pointers derived from the same base.
204 ///
205 /// A particular Use will only be visited once, but a User may be visited
206 /// multiple times, once per Use. This visits may notably have different
207 /// offsets.
208 ///
209 /// All visit methods on the underlying InstVisitor return a boolean. This
210 /// return short-circuits the visit, stopping it immediately.
211 ///
212 /// FIXME: Generalize this for all values rather than just instructions.
213 template <typename DerivedT>
214 class PtrUseVisitor : protected InstVisitor<DerivedT>,
215                       public detail::PtrUseVisitorBase {
216   friend class InstVisitor<DerivedT>;
217 
218   using Base = InstVisitor<DerivedT>;
219 
220 public:
221   PtrUseVisitor(const DataLayout &DL) : PtrUseVisitorBase(DL) {
222     static_assert(std::is_base_of<PtrUseVisitor, DerivedT>::value,
223                   "Must pass the derived type to this template!");
224   }
225 
226   /// Recursively visit the uses of the given pointer.
227   /// \returns An info struct about the pointer. See \c PtrInfo for details.
228   /// We may also need to process Argument pointers, so the input uses is
229   /// a common Value type.
230   PtrInfo visitPtr(Value &I) {
231     // This must be a pointer type. Get an integer type suitable to hold
232     // offsets on this pointer.
233     // FIXME: Support a vector of pointers.
234     assert(I.getType()->isPointerTy());
235     assert(isa<Instruction>(I) || isa<Argument>(I));
236     IntegerType *IntIdxTy = cast<IntegerType>(DL.getIndexType(I.getType()));
237     IsOffsetKnown = true;
238     Offset = APInt(IntIdxTy->getBitWidth(), 0);
239     PI.reset();
240 
241     // Enqueue the uses of this pointer.
242     enqueueUsers(I);
243 
244     // Visit all the uses off the worklist until it is empty.
245     while (!Worklist.empty()) {
246       UseToVisit ToVisit = Worklist.pop_back_val();
247       U = ToVisit.UseAndIsOffsetKnown.getPointer();
248       IsOffsetKnown = ToVisit.UseAndIsOffsetKnown.getInt();
249       if (IsOffsetKnown)
250         Offset = std::move(ToVisit.Offset);
251 
252       Instruction *I = cast<Instruction>(U->getUser());
253       static_cast<DerivedT*>(this)->visit(I);
254       if (PI.isAborted())
255         break;
256     }
257     return PI;
258   }
259 
260 protected:
261   void visitStoreInst(StoreInst &SI) {
262     if (SI.getValueOperand() == U->get())
263       PI.setEscaped(&SI);
264   }
265 
266   void visitBitCastInst(BitCastInst &BC) {
267     enqueueUsers(BC);
268   }
269 
270   void visitAddrSpaceCastInst(AddrSpaceCastInst &ASC) {
271     enqueueUsers(ASC);
272   }
273 
274   void visitPtrToIntInst(PtrToIntInst &I) {
275     PI.setEscaped(&I);
276   }
277 
278   void visitGetElementPtrInst(GetElementPtrInst &GEPI) {
279     if (GEPI.use_empty())
280       return;
281 
282     // If we can't walk the GEP, clear the offset.
283     if (!adjustOffsetForGEP(GEPI)) {
284       IsOffsetKnown = false;
285       Offset = APInt();
286     }
287 
288     // Enqueue the users now that the offset has been adjusted.
289     enqueueUsers(GEPI);
290   }
291 
292   void visitStructuredGEPInst(StructuredGEPInst &SGEP) {
293     if (SGEP.use_empty())
294       return;
295 
296     if (!adjustOffsetForSGEP(SGEP)) {
297       IsOffsetKnown = false;
298       Offset = APInt();
299     }
300     enqueueUsers(SGEP);
301   }
302 
303   // No-op intrinsics which we know don't escape the pointer to logic in
304   // some other function.
305   void visitMemIntrinsic(MemIntrinsic &I) {}
306   void visitIntrinsicInst(IntrinsicInst &II) {
307     if (auto *SGEP = dyn_cast<StructuredGEPInst>(&II))
308       return visitStructuredGEPInst(*SGEP);
309 
310     switch (II.getIntrinsicID()) {
311     default:
312       return Base::visitIntrinsicInst(II);
313 
314     // We escape pointers used by a fake_use to prevent SROA from transforming
315     // them.
316     case Intrinsic::fake_use:
317       PI.setEscaped(&II);
318       return;
319 
320     case Intrinsic::lifetime_start:
321     case Intrinsic::lifetime_end:
322       return; // No-op intrinsics.
323     }
324   }
325 
326   // Generically, arguments to calls and invokes escape the pointer to some
327   // other function. Mark that.
328   void visitCallBase(CallBase &CB) {
329     PI.setEscaped(&CB);
330     Base::visitCallBase(CB);
331   }
332 };
333 
334 } // end namespace llvm
335 
